package com.google.gson;

import com.google.gson.Gson;
import com.google.gson.JsonIOException;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

import java.io.IOException;
import java.lang.reflect.Method;
import java.lang.reflect.Modifier;

import static org.junit.jupiter.api.Assertions.*;

class GsonToJsonTest {

  private Gson gson;

  @BeforeEach
  void setUp() {
    gson = new Gson();
  }

  @Test
  void toJson_withNonNullObject_callsOverloadedToJson() throws Exception {
    Object src = "test string";
    Appendable writer = new Appendable() {
      private final StringBuilder sb = new StringBuilder();

      @Override
      public Appendable append(CharSequence csq) {
        sb.append(csq);
        return this;
      }

      @Override
      public Appendable append(CharSequence csq, int start, int end) {
        sb.append(csq, start, end);
        return this;
      }

      @Override
      public Appendable append(char c) {
        sb.append(c);
        return this;
      }

      @Override
      public String toString() {
        return sb.toString();
      }
    };

    // Spy on Gson instance to verify private method call
    Gson spyGson = Mockito.spy(gson);

    // Call public method
    spyGson.toJson(src, writer);

    // Verify private toJson(Object, Type, Appendable) was called with src, src.getClass(), writer
    // We cannot verify private methods directly with Mockito.
    // Instead, we use reflection to invoke the private method and verify spy behavior indirectly.
    Method toJsonMethod = Gson.class.getDeclaredMethod("toJson", Object.class, java.lang.reflect.Type.class, Appendable.class);
    toJsonMethod.setAccessible(true);

    // To verify the private method was called, we use Mockito's doCallRealMethod on spy for the private method
    // But since Mockito cannot spy on private methods directly, we verify the public call behavior instead.
    // So here, we just assert that the output in writer matches expected JSON string.

    String expectedJson = "\"test string\"";
    assertEquals(expectedJson, writer.toString());
  }

  @Test
  void toJson_withNullObject_callsToJsonWithJsonNullInstance() throws Exception {
    Appendable writer = new Appendable() {
      private final StringBuilder sb = new StringBuilder();

      @Override
      public Appendable append(CharSequence csq) {
        sb.append(csq);
        return this;
      }

      @Override
      public Appendable append(CharSequence csq, int start, int end) {
        sb.append(csq, start, end);
        return this;
      }

      @Override
      public Appendable append(char c) {
        sb.append(c);
        return this;
      }

      @Override
      public String toString() {
        return sb.toString();
      }
    };

    Gson spyGson = Mockito.spy(gson);

    spyGson.toJson(null, writer);

    // Since private method calls cannot be verified directly, verify output instead
    String expectedJson = "null";
    assertEquals(expectedJson, writer.toString());
  }

  @Test
  void toJson_withNullObject_doesNotThrow() {
    Appendable writer = new StringBuilder();

    assertDoesNotThrow(() -> gson.toJson(null, writer));
  }

  @Test
  void toJson_withNonNullObject_doesNotThrow() {
    Appendable writer = new StringBuilder();

    assertDoesNotThrow(() -> gson.toJson("string", writer));
  }

  @Test
  void toJson_withAppendableThatThrows_throwsJsonIOException() {
    Appendable throwingAppendable = new Appendable() {
      @Override
      public Appendable append(CharSequence csq) throws IOException {
        throw new IOException("fail");
      }

      @Override
      public Appendable append(CharSequence csq, int start, int end) throws IOException {
        throw new IOException("fail");
      }

      @Override
      public Appendable append(char c) throws IOException {
        throw new IOException("fail");
      }
    };

    assertThrows(JsonIOException.class, () -> gson.toJson("string", throwingAppendable));
  }
}
